inline bool qwcIswprint( const u32 cp )
{
  if ( cp >= 0x110000 ) return false;
  const u8* block = kIswprintBlocks[kIswprintIndex[cp >> 8]];
  return ( block[( cp & 0xFF ) >> 3] >> ( cp & 7 ) ) & 1;
}

